import{_ as e,a as t,b as i}from"./chunks/配置渠道内容.HzNkdrom.js";import{_ as o,o as s,c as n,a2 as r}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Aggiungere un canale GitLab Packages","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/upload/gitlab-packages.md","filePath":"it-IT/upload/gitlab-packages.md","lastUpdated":1781962217000}'),c={name:"it-IT/upload/gitlab-packages.md"};function l(d,a,p,g,m,u){return s(),n("div",null,[...a[0]||(a[0]=[r('<h1 id="aggiungere-un-canale-gitlab-packages" tabindex="-1">Aggiungere un canale GitLab Packages <a class="header-anchor" href="#aggiungere-un-canale-gitlab-packages" aria-label="Permalink to &quot;Aggiungere un canale GitLab Packages&quot;">​</a></h1><h2 id="prima-di-iniziare" tabindex="-1">Prima di iniziare <a class="header-anchor" href="#prima-di-iniziare" aria-label="Permalink to &quot;Prima di iniziare&quot;">​</a></h2><p>Servono solo tre cose:</p><table tabindex="0"><thead><tr><th>Requisito</th><th>Scopo</th></tr></thead><tbody><tr><td>Account GitLab</td><td>Per generare un access token e possedere il progetto.</td></tr><tr><td>GitLab Personal Access Token</td><td>Permette a ImgBed di usare la GitLab API, creare progetti e caricare file in Generic Packages.</td></tr><tr><td>Nome progetto</td><td>Puoi inserire anche solo il nome, per esempio <code>imgbed</code>.</td></tr></tbody></table><h2 id="configurazione" tabindex="-1">Configurazione <a class="header-anchor" href="#configurazione" aria-label="Permalink to &quot;Configurazione&quot;">​</a></h2><h3 id="passaggio-1-accedi-a-gitlab-e-crea-un-access-token" tabindex="-1">Passaggio 1: accedi a GitLab e crea un Access Token <a class="header-anchor" href="#passaggio-1-accedi-a-gitlab-e-crea-un-access-token" aria-label="Permalink to &quot;Passaggio 1: accedi a GitLab e crea un Access Token&quot;">​</a></h3><ol><li>Accedi a GitLab.</li><li>Clicca sull&#39;avatar in alto a destra e apri <code>Preferences</code>.</li><li>Apri <code>Access Tokens</code> dalla barra laterale.</li><li>Dai al token un nome riconoscibile.</li><li>Scegli una scadenza adatta al tuo modo di gestire la manutenzione.</li><li>Seleziona lo scope <code>api</code>.</li><li>Copia e salva subito il token appena viene creato.</li></ol><p><img src="'+e+'" alt="Crea token legacy" loading="lazy"></p><p><img src="'+t+'" alt="Seleziona permessi token" loading="lazy"></p><h2 id="passaggio-2-compila-il-canale-gitlab-packages-in-imgbed" tabindex="-1">Passaggio 2: compila il canale GitLab Packages in ImgBed <a class="header-anchor" href="#passaggio-2-compila-il-canale-gitlab-packages-in-imgbed" aria-label="Permalink to &quot;Passaggio 2: compila il canale GitLab Packages in ImgBed&quot;">​</a></h2><p>Dopo aver scelto <code>GitLab Packages</code> nelle Impostazioni di caricamento, compila:</p><table tabindex="0"><thead><tr><th>Campo UI</th><th>Cosa inserire</th></tr></thead><tbody><tr><td>Nome canale</td><td>Un nome a tua scelta, per esempio <code>GitLabPrimary</code>.</td></tr><tr><td>Access Token</td><td>Il GitLab Personal Access Token appena creato.</td></tr><tr><td>Nome progetto</td><td>Un nome breve come <code>imgbed</code>, oppure un percorso completo come <code>username/imgbed</code>.</td></tr><tr><td>Repository privato</td><td>Attiva o disattiva in base alle tue esigenze.</td></tr><tr><td>Nota</td><td>Opzionale, per esempio <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+i+`" alt="Configura canale" loading="lazy"></p><h2 id="passaggio-3-salva-il-canale" tabindex="-1">Passaggio 3: salva il canale <a class="header-anchor" href="#passaggio-3-salva-il-canale" aria-label="Permalink to &quot;Passaggio 3: salva il canale&quot;">​</a></h2><p>Dopo aver compilato i campi, salva.</p><p>Il sistema gestisce automaticamente questi dettagli:</p><table tabindex="0"><thead><tr><th>Comportamento</th><th>Descrizione</th></tr></thead><tbody><tr><td>Nome progetto breve</td><td>ImgBed identifica l&#39;account GitLab corrente e lo trasforma in un percorso progetto completo.</td></tr><tr><td>Percorso progetto completo</td><td>ImgBed usa <code>username/project</code> esattamente come inserito.</td></tr><tr><td>Controllo progetto</td><td>Se usi il percorso dell&#39;account personale corrente, ImgBed crea il progetto se non esiste. Se inserisci manualmente un percorso completo, lo usa direttamente.</td></tr><tr><td>Pubblico/privato</td><td>La visibilità del progetto viene sincronizzata con l&#39;interruttore corrente.</td></tr></tbody></table><h2 id="checklist-rapida" tabindex="-1">Checklist rapida <a class="header-anchor" href="#checklist-rapida" aria-label="Permalink to &quot;Checklist rapida&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Accedi a GitLab</span></span>
<span class="line"><span>-&gt; Crea un Access Token</span></span>
<span class="line"><span>-&gt; Seleziona solo lo scope api</span></span>
<span class="line"><span>-&gt; Torna in ImgBed e inserisci token e nome progetto</span></span>
<span class="line"><span>-&gt; Salva</span></span>
<span class="line"><span>-&gt; Se inserisci solo il nome progetto, ImgBed aggiunge automaticamente lo username corrente</span></span>
<span class="line"><span>-&gt; Se inserisci username/project, ImgBed lo usa così com&#39;è</span></span>
<span class="line"><span>-&gt; Carica un&#39;immagine di prova</span></span></code></pre></div>`,19)])])}const P=o(c,[["render",l]]);export{k as __pageData,P as default};
